const MAILMAN_CORE_EMAIL = "mailman-core@example.com";
const DEPARTMENT_MAILBOXES = {
  admissions: { department_name: "입학처", department_email: "admissions@example.com" },
  finance_team: { department_name: "재무팀", department_email: "finance@example.com" },
  academic_records: { department_name: "학적팀", department_email: "academic@example.com" },
  international_team: { department_name: "국제팀", department_email: "international@example.com" }
};

function readHeader(headers, name) {
  const target = String(name || "").toLowerCase();
  if (!headers) return "";

  if (Array.isArray(headers)) {
    const found = headers.find((header) => String(header.name || "").toLowerCase() === target);
    return found ? String(found.value || "") : "";
  }

  const direct = headers[name] || headers[target];
  if (direct) return String(direct);

  const key = Object.keys(headers).find((headerName) => headerName.toLowerCase() === target);
  return key ? String(headers[key] || "") : "";
}

function firstNonEmpty(values) {
  for (const value of values) {
    if (value === undefined || value === null) continue;
    if (typeof value === "object") continue;
    const text = String(value).trim();
    if (text) return text;
  }
  return "";
}

const EMAIL_PATTERN = /[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi;

function extractEmails(value) {
  if (value === undefined || value === null) return [];

  if (typeof value === "object") {
    const objectCandidates = [value.email, value.address, value.value, value.text, value.to, value.cc, value.from];
    const found = [];
    for (const candidate of objectCandidates) {
      found.push(...extractEmails(candidate));
    }

    try {
      found.push(...extractEmails(JSON.stringify(value)));
    } catch (error) {}

    return [...new Set(found.map((email) => email.toLowerCase()))];
  }

  const text = String(value || "");
  const matches = text.match(EMAIL_PATTERN) || [];
  return [...new Set(matches.map((email) => email.toLowerCase()))];
}

function extractEmail(value) {
  return extractEmails(value)[0] || "";
}

function normalizeFromEmail(values) {
  for (const value of values) {
    const email = extractEmail(value);
    if (email) return email;
  }
  return "unknown_sender";
}

function normalizeDate(value) {
  if (value === undefined || value === null || value === "") {
    return { received_at_utc: "", received_at_kst: "", received_at: "" };
  }

  let date;
  if (typeof value === "number" || /^\d+$/.test(String(value))) {
    const numeric = Number(value);
    date = new Date(numeric > 9999999999 ? numeric : numeric * 1000);
  } else {
    date = new Date(value);
  }

  if (Number.isNaN(date.getTime())) {
    return { received_at_utc: "", received_at_kst: "", received_at: "" };
  }

  const received_at_utc = date.toISOString();
  const kstDate = new Date(date.getTime() + 9 * 60 * 60 * 1000);
  const pad = (number) => String(number).padStart(2, "0");
  const received_at_kst = kstDate.getUTCFullYear() + "-" + pad(kstDate.getUTCMonth() + 1) + "-" + pad(kstDate.getUTCDate()) + " " + pad(kstDate.getUTCHours()) + ":" + pad(kstDate.getUTCMinutes()) + ":" + pad(kstDate.getUTCSeconds()) + " KST";

  return { received_at_utc, received_at_kst, received_at: received_at_kst };
}

function decodeBase64Url(value) {
  if (!value || typeof Buffer === "undefined") return "";
  try {
    const normalized = String(value).replace(/-/g, "+").replace(/_/g, "/");
    return Buffer.from(normalized, "base64").toString("utf8");
  } catch (error) {
    return "";
  }
}

function collectPartBodies(parts) {
  if (!Array.isArray(parts)) return [];

  const bodies = [];
  for (const part of parts) {
    if (!part) continue;
    const mimeType = String(part.mimeType || "").toLowerCase();
    const data = part.body && part.body.data ? decodeBase64Url(part.body.data) : "";

    if (data && (mimeType.includes("text/plain") || mimeType.includes("text/html"))) {
      bodies.push(data);
    }

    bodies.push(...collectPartBodies(part.parts));
  }

  return bodies;
}

function stripHtml(value) {
  return String(value || "")
    .replace(/<script[\s\S]*?<\/script>/gi, " ")
    .replace(/<style[\s\S]*?<\/style>/gi, " ")
    .replace(/<[^>]+>/g, " ")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/\s+/g, " ")
    .trim();
}

function bodyValue(value, source) {
  if (value === undefined || value === null || value === false) return { text: "", source: "" };
  if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
    const text = String(value).trim();
    return text ? { text, source } : { text: "", source: "" };
  }
  if (typeof value !== "object") return { text: "", source: "" };

  const candidates = [
    ["textPlain", value.textPlain],
    ["plainText", value.plainText],
    ["text", value.text],
    ["body", value.body],
    ["content", value.content],
    ["data", value.data],
    ["textHtml", value.textHtml],
    ["html", value.html],
    ["snippet", value.snippet]
  ];

  for (const candidate of candidates) {
    const nested = bodyValue(candidate[1], source + "." + candidate[0]);
    if (nested.text) return nested;
  }
  return { text: "", source: "" };
}

function collectPartBodyCandidates(parts, prefix) {
  if (!Array.isArray(parts)) return [];

  const candidates = [];
  parts.forEach((part, index) => {
    if (!part) return;
    const path = prefix + "[" + index + "]";
    const mimeType = String(part.mimeType || "").toLowerCase();
    const dataText = part.body && part.body.data ? decodeBase64Url(part.body.data) : "";
    if (dataText && mimeType.includes("text/plain")) candidates.push({ text: dataText, source: path + ".text/plain" });
    if (dataText && mimeType.includes("text/html")) candidates.push({ text: dataText, source: path + ".text/html" });
    candidates.push(...collectPartBodyCandidates(part.parts, path + ".parts"));
  });
  return candidates;
}

function normalizeBody(json, payload) {
  const partCandidates = [
    ...collectPartBodyCandidates(payload.parts, "payload.parts"),
    ...collectPartBodyCandidates(json.message && json.message.payload && json.message.payload.parts, "message.payload.parts"),
    ...collectPartBodyCandidates(json.data && json.data.payload && json.data.payload.parts, "data.payload.parts")
  ];
  const partPlain = partCandidates.find((candidate) => candidate.source.includes("text/plain")) || { text: "", source: "" };
  const partHtml = partCandidates.find((candidate) => candidate.source.includes("text/html")) || { text: "", source: "" };
  const payloadBody = payload.body && payload.body.data ? { text: decodeBase64Url(payload.body.data), source: "payload.body.data" } : { text: "", source: "" };

  const candidates = [
    bodyValue(json.textPlain, "json.textPlain"),
    bodyValue(json.text, "json.text"),
    bodyValue(json.plainText, "json.plainText"),
    partPlain,
    bodyValue(json.body, "json.body"),
    payloadBody,
    bodyValue(json.textHtml, "json.textHtml"),
    bodyValue(json.html === false ? "" : json.html, "json.html"),
    partHtml,
    bodyValue(json.snippet, "json.snippet")
  ];

  const selected = candidates.find((candidate) => candidate && String(candidate.text || "").trim()) || { text: "", source: "not_found" };
  normalizeBody.lastDebug = {
    source: selected.source,
    length: String(selected.text || "").length,
    checked_sources: candidates.map((candidate) => candidate.source).filter(Boolean),
    json_html_is_false: json.html === false
  };
  return stripHtml(selected.text);
}

function collectAttachmentParts(parts) {
  if (!Array.isArray(parts)) return [];

  const attachments = [];
  for (const part of parts) {
    if (!part) continue;
    if (part.filename) attachments.push(part);
    attachments.push(...collectAttachmentParts(part.parts));
  }
  return attachments;
}

function normalizeExistingAttachments(value) {
  if (!Array.isArray(value)) return [];
  return value
    .filter((attachment) => attachment && (attachment.filename || attachment.fileName || attachment.name || attachment.attachment_id || attachment.attachmentId))
    .map((attachment) => ({
      filename: attachment.filename || attachment.fileName || attachment.name || "",
      mime_type: attachment.mime_type || attachment.mimeType || attachment.contentType || "",
      binary_property: attachment.binary_property || attachment.binaryProperty || attachment.binaryPropertyName || "",
      attachment_id: attachment.attachment_id || attachment.attachmentId || attachment.id || ""
    }));
}

function normalizeAttachments(item, payload) {
  const binary = item.binary || {};
  const binaryAttachments = Object.keys(binary).map((key) => ({
    filename: binary[key].fileName || key,
    mime_type: binary[key].mimeType || "",
    binary_property: key
  }));

  if (binaryAttachments.length > 0) return binaryAttachments;

  const existingAttachments = normalizeExistingAttachments((item.json || {}).attachments);
  if (existingAttachments.length > 0) return existingAttachments;

  return collectAttachmentParts([payload])
    .map((part) => ({
      filename: part.filename || "",
      mime_type: part.mimeType || "",
      attachment_id: part.body && part.body.attachmentId ? part.body.attachmentId : ""
    }));
}

function departmentByEmail(email) {
  const normalized = String(email || "").toLowerCase();
  return Object.keys(DEPARTMENT_MAILBOXES).find((departmentId) => DEPARTMENT_MAILBOXES[departmentId].department_email.toLowerCase() === normalized) || "";
}

function inferDepartmentIntake(headers, json, subject, body) {
  const routingTextValues = [
    json.to,
    json.cc,
    json.deliveredTo,
    json.xForwardedTo,
    readHeader(headers, "To"),
    readHeader(headers, "Cc"),
    readHeader(headers, "Delivered-To"),
    readHeader(headers, "X-Original-To"),
    readHeader(headers, "X-Forwarded-To"),
    readHeader(headers, "X-Forwarded-For")
  ];
  const routingEmails = [...new Set(routingTextValues.flatMap((value) => extractEmails(value)))];
  const sourceDepartmentId = routingEmails.map(departmentByEmail).find(Boolean) || "";
  const sourceDepartment = sourceDepartmentId ? DEPARTMENT_MAILBOXES[sourceDepartmentId] : null;
  const coreWasRecipient = routingEmails.includes(MAILMAN_CORE_EMAIL.toLowerCase());
  const signalText = [subject, body, ...routingTextValues].join(" ").toLowerCase();
  const forwardedHint = signalText.includes("forwarded message") || signalText.includes("전달된 메시지") || Boolean(sourceDepartmentId);

  return {
    core_email: MAILMAN_CORE_EMAIL,
    source_mailbox: sourceDepartmentId || "core_credential_mailbox",
    intake_channel: sourceDepartmentId ? "forwarded_from_department" : "direct_to_core",
    is_forwarded_to_core: Boolean(sourceDepartmentId || forwardedHint),
    original_recipient_department_id: sourceDepartmentId,
    original_recipient_department_name: sourceDepartment ? sourceDepartment.department_name : "",
    original_recipient_email: sourceDepartment ? sourceDepartment.department_email : "",
    core_was_recipient: coreWasRecipient,
    intake_detected_emails: routingEmails
  };
}

function isMailmanGeneratedSubject(subject) {
  const text = String(subject || "");
  return text.includes("[Mailman 자동배정]") || text.includes("[Mailman 자동응답]");
}

return items.map((item) => {
  const json = item.json || {};
  const payload = json.payload || {};
  const headers = payload.headers || json.headers || [];
  const rawSubject = firstNonEmpty([json.subject, readHeader(headers, "Subject")]);
  const subject = rawSubject || "(no subject)";

  if (isMailmanGeneratedSubject(subject)) {
    return null;
  }

  const receivedAtRaw = firstNonEmpty([json.date, json.received_at, readHeader(headers, "Date"), json.internalDate]);
  const receivedAt = normalizeDate(receivedAtRaw);
  const messageId = firstNonEmpty([json.id, json.messageId, json.message_id, readHeader(headers, "Message-ID")]);
  const body = normalizeBody(json, payload);
  const bodyDebug = normalizeBody.lastDebug || { source: "not_found", length: 0, checked_sources: [], json_html_is_false: json.html === false };
  const fromEmail = normalizeFromEmail([json.from, json.sender, json.replyTo, readHeader(headers, "From"), readHeader(headers, "Reply-To")]);
  const intake = inferDepartmentIntake(headers, json, subject, body);

  if (!messageId && !json.id && !json.messageId && !json.threadId && !rawSubject && !body) {
    return null;
  }

  return {
    json: {
      message_id: messageId,
      from_email: fromEmail,
      subject,
      body,
      body_debug: bodyDebug,
      received_at: receivedAt.received_at,
      received_at_utc: receivedAt.received_at_utc,
      received_at_kst: receivedAt.received_at_kst,
      attachments: normalizeAttachments(item, payload),
      department_mailboxes: DEPARTMENT_MAILBOXES,
      ...intake
    },
    binary: item.binary || {}
  };
}).filter(Boolean);

return items.map((item) => {
  item.json.classify_and_draft = {
    status: 'gmail_trigger_normalized',
    department_id: 'mock_department',
    department_name: 'Mock 검토 부서',
    confidence: 0.9,
    reason: 'Step 11-1에서는 Gmail Trigger 데이터 정규화만 확인하므로 mock classification response를 사용함',
    auto_reply: false,
    manual_review: false,
    draft_reply: 'Gmail Trigger 수신 및 정규화 테스트가 완료되었습니다. 실제 답변 초안은 다음 Step의 Upstage API 연결 후 생성합니다.',
    routing_summary: 'Gmail Trigger로 들어온 실제 메일을 표준 구조로 변환하는 데모 경로입니다.'
  };
  return item;
});

return items.map((item) => {
  const email = item.json || {};
  const attachments = Array.isArray(email.attachments) ? email.attachments : [];
  const firstAttachment = attachments[0] || {};
  const binaryProperty = firstAttachment.binary_property || '';
  const hasBinary = Boolean(binaryProperty && item.binary && item.binary[binaryProperty]);
  const hasAttachmentIdOnly = Boolean(!hasBinary && firstAttachment.attachment_id);

  item.json.document_parse_input = {
    attachment_count: attachments.length,
    selected_attachment: firstAttachment,
    binary_property: binaryProperty,
    has_binary: hasBinary,
    has_attachment_id_only: hasAttachmentIdOnly,
    todo: hasAttachmentIdOnly ? 'Gmail attachment fetch is required before Document Parse because only attachment_id is available.' : ''
  };

  if (!hasBinary) {
    item.json.document_parse_status = 'skipped_or_failed';
    item.json.document_text = '';
    item.json.document_summary = '';
    item.json.parsed_attachments = [];
    item.json.document_parse_error = hasAttachmentIdOnly
      ? 'Gmail attachment fetch required before binary upload to Upstage Document Parse.'
      : 'No n8n binary data found for selected attachment.';
    item.json.manual_review = false;
  }

  return item;
});

return items.map((item) => {
  const json = item.json || {};
  const response = json.document_parse_api_response || json;
  const hadPreparedFailure = json.document_parse_status === 'skipped_or_failed';
  const httpError = response.error || response.message === 'Authorization failed' || response.statusCode >= 400;

  if (hadPreparedFailure || httpError) {
    item.json.document_parse_status = 'skipped_or_failed';
    item.json.document_text = '';
    item.json.document_summary = '';
    item.json.parsed_attachments = [];
    item.json.document_parse_error = json.document_parse_error || (response.error && (response.error.message || JSON.stringify(response.error))) || response.message || 'Document Parse API request failed.';
    item.json.manual_review = false;
    return item;
  }

  function stringifyText(value) {
    if (value === undefined || value === null || value === false) return '';
    if (typeof value === 'string') return value;
    if (typeof value === 'number' || typeof value === 'boolean') return String(value);
    if (Array.isArray(value)) return value.map(stringifyText).filter(Boolean).join('\n');
    if (typeof value === 'object') {
      const nested = [value.text, value.markdown, value.html, value.content, value.value, value.description]
        .map(stringifyText)
        .filter(Boolean);
      if (nested.length > 0) return nested.join('\n');
      return '';
    }
    return '';
  }

  const textCandidates = [
    response.text,
    response.content && response.content.text,
    response.content && response.content.markdown,
    response.content && response.content.html,
    response.content,
    response.markdown,
    response.html,
    response.document_text,
    response.parsed_text,
    response.result && response.result.text,
    response.result && response.result.content,
    response.pages,
    response.elements
  ].map(stringifyText).filter(Boolean);

  const documentText = textCandidates.length > 0 ? textCandidates[0] : JSON.stringify(response);
  const selectedAttachment = json.document_parse_input && json.document_parse_input.selected_attachment ? json.document_parse_input.selected_attachment : {};

  item.json.document_parse_status = 'success';
  item.json.document_text = documentText;
  item.json.document_summary = documentText.slice(0, 500);
  item.json.parsed_attachments = [
    {
      filename: selectedAttachment.filename || '',
      mime_type: selectedAttachment.mime_type || '',
      parse_status: 'success'
    }
  ];
  item.json.document_parse_error = '';

  return item;
});

return items.map((item) => {
  item.json.document_parse_status = 'skipped_or_failed';
  item.json.document_text = '';
  item.json.document_summary = '';
  item.json.parsed_attachments = [];
  item.json.document_parse_error = Array.isArray(item.json.attachments) && item.json.attachments.length > 0
    ? 'Document Parse skipped or failed before API request.'
    : 'No attachments found. Document Parse skipped.';
  return item;
});

const VIRTUAL_DEPARTMENT_EMAILS = {
  admissions: 'admissions-demo@example.com',
  finance_team: 'finance-demo@example.com',
  academic_records: 'records-demo@example.com',
  international_team: 'international-demo@example.com'
};

const DEPARTMENT_NAMES = {
  admissions: '입학처',
  finance_team: '재무팀',
  academic_records: '학적팀',
  international_team: '국제팀'
};

function stringify(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string') return value;
  try {
    return JSON.stringify(value);
  } catch (error) {
    return String(value);
  }
}

function inferSourceMailbox(email) {
  if (email.source_mailbox) return email.source_mailbox;
  if (email.original_recipient_department_id) return email.original_recipient_department_id;

  const text = [
    email.subject,
    email.body,
    email.from_email,
    email.original_recipient_email,
    stringify(email.intake_detected_emails),
    stringify(email.attachments)
  ].join(' ').toLowerCase();

  for (const departmentId of Object.keys(VIRTUAL_DEPARTMENT_EMAILS)) {
    if (text.includes(VIRTUAL_DEPARTMENT_EMAILS[departmentId].toLowerCase())) {
      return departmentId;
    }
  }

  return 'core_credential_mailbox';
}

function inferIntakeChannel(sourceMailbox, email) {
  if (email.intake_channel) return email.intake_channel;
  if (!sourceMailbox || sourceMailbox === 'core_credential_mailbox') return 'direct_to_core';
  return 'forwarded_from_department';
}

return items.map((item) => {
  const email = item.json || {};
  const sourceMailbox = inferSourceMailbox(email);
  const intakeChannel = inferIntakeChannel(sourceMailbox, email);
  const isForwardedToCore = email.is_forwarded_to_core === true || intakeChannel === 'forwarded_from_department';
  const originalRecipientDepartmentId = email.original_recipient_department_id || (sourceMailbox !== 'core_credential_mailbox' ? sourceMailbox : '');
  const originalRecipientDepartmentName = email.original_recipient_department_name || DEPARTMENT_NAMES[originalRecipientDepartmentId] || '';
  const originalRecipientEmail = email.original_recipient_email || VIRTUAL_DEPARTMENT_EMAILS[originalRecipientDepartmentId] || '';

  const originalEmailContext = {
    message_id: email.message_id || '',
    from_email: email.from_email || '',
    subject: email.subject || '',
    body: email.body || '',
    received_at: email.received_at || '',
    received_at_utc: email.received_at_utc || '',
    received_at_kst: email.received_at_kst || '',
    attachments: Array.isArray(email.attachments) ? email.attachments : [],
    source_mailbox: sourceMailbox,
    intake_channel: intakeChannel,
    is_forwarded_to_core: isForwardedToCore,
    original_recipient_department_id: originalRecipientDepartmentId,
    original_recipient_department_name: originalRecipientDepartmentName,
    original_recipient_email: originalRecipientEmail,
    core_email: email.core_email || 'mailman-core-demo@example.com',
    document_parse_status: email.document_parse_status || '',
    document_text: email.document_text || '',
    document_summary: email.document_summary || '',
    parsed_attachments: Array.isArray(email.parsed_attachments) ? email.parsed_attachments : [],
    document_parse_error: email.document_parse_error || ''
  };

  const extractionInput = {
    core_context: 'This email was received by the Mailman Core mailbox. It may have been sent directly to Core or automatically forwarded from a department mailbox.',
    ...originalEmailContext,
    virtual_department_emails: VIRTUAL_DEPARTMENT_EMAILS,
    extraction_schema: {
      student_name: '',
      student_id: '',
      department: '',
      grade: '',
      inquiry_type: '',
      document_type: '',
      request_summary: '',
      requested_action: '',
      confidence: 0.0
    }
  };

  item.json = {
    ...email,
    ...originalEmailContext,
    source_mailbox: sourceMailbox,
    intake_channel: intakeChannel,
    is_forwarded_to_core: isForwardedToCore,
    original_recipient_department_id: originalRecipientDepartmentId,
    original_recipient_department_name: originalRecipientDepartmentName,
    original_recipient_email: originalRecipientEmail,
    virtual_department_emails: VIRTUAL_DEPARTMENT_EMAILS,
    original_email_context: originalEmailContext,
    extraction_input: extractionInput,
    information_extract_request: {
      schema_source: 'prompts/extraction_schema.json',
      input_text: [
        'Subject: ' + extractionInput.subject,
        'Body: ' + extractionInput.body,
        'Document Parse Status: ' + extractionInput.document_parse_status,
        'Document Summary: ' + extractionInput.document_summary,
        'Document Text: ' + extractionInput.document_text,
        'Source Mailbox: ' + extractionInput.source_mailbox,
        'Intake Channel: ' + extractionInput.intake_channel,
        'Original Recipient Department: ' + extractionInput.original_recipient_department_name,
        'Original Recipient Email: ' + extractionInput.original_recipient_email
      ].join('\n\n'),
      schema: extractionInput.extraction_schema,
      todo: 'Confirm Upstage Information Extract endpoint, method, schema field name, input text field name, and response format in official API Reference.'
    }
  };

  return item;
});

function pickPayload(response) {
  if (!response || typeof response !== 'object') return {};
  return response.extracted || response.result || response.data || response.output || response;
}

function asNumber(value) {
  const number = Number(value);
  return Number.isFinite(number) ? number : 0;
}

function arrayOrEmpty(value) {
  return Array.isArray(value) ? value : [];
}

function upstreamJson(index) {
  try {
    if (typeof $items === 'function') {
      const upstream = $items('Prepare Information Extract Input Function Node', 0, 0) || [];
      return (upstream[index] && upstream[index].json) || {};
    }
  } catch (error) {}
  try {
    if (typeof $node !== 'undefined' && $node['Prepare Information Extract Input Function Node'] && $node['Prepare Information Extract Input Function Node'].json) {
      return $node['Prepare Information Extract Input Function Node'].json;
    }
  } catch (error) {}
  return {};
}

function restoreOriginalFields(json, index) {
  const upstream = upstreamJson(index);
  const original = json.original_email_context || json.extraction_input || upstream.original_email_context || upstream.extraction_input || upstream || {};
  return {
    message_id: json.message_id || original.message_id || '',
    from_email: json.from_email || original.from_email || '',
    subject: json.subject || original.subject || '',
    body: json.body || original.body || '',
    received_at: json.received_at || original.received_at || '',
    received_at_utc: json.received_at_utc || original.received_at_utc || '',
