    const parsed = parseJsonLoose(rawText);
    const raw = parsed.expected_json_output && typeof parsed.expected_json_output === 'object' ? parsed.expected_json_output : parsed;
    const normalizedAction = normalizeCoreAction(raw.core_action || parsed.core_action || '');
