function includesAny(text, keywords) {
  return keywords.some((keyword) => text.includes(keyword.toLowerCase()));
}

function inferDepartment(text) {
  const t = String(text || '').toLowerCase();
  if (includesAny(t, ['\uAD6D\uC81C', '\uC720\uD559\uC0DD', '\uBE44\uC790', '\uAD50\uD658\uD559\uC0DD', '\uD574\uC678', 'international', 'visa', 'exchange student'])) return 'international_team';
  if (includesAny(t, ['\uC785\uD559', '\uC6D0\uC11C', '\uC9C0\uC6D0', 'admission', 'application'])) return 'admissions';
  if (includesAny(t, ['\uB4F1\uB85D\uAE08', '\uB0A9\uBD80', '\uD658\uBD88', '\uACB0\uC81C', 'tuition', 'payment', 'refund'])) return 'finance_team';
  if (includesAny(t, ['\uD559\uC801', '\uC131\uC801\uD45C', '\uC99D\uBA85\uC11C', '\uC878\uC5C5', '\uD734\uD559', '\uBCF5\uD559', 'transcript', 'certificate', 'graduation'])) return 'academic_records';
  if (includesAny(t, ['\uC7A5\uD559\uAE08', 'scholarship'])) return 'finance_team';
  if (includesAny(t, ['\uAE30\uC219\uC0AC', 'dormitory'])) return 'academic_records';
  if (includesAny(t, ['\uC218\uAC15\uC2E0\uCCAD', '\uD559\uC0AC\uC77C\uC815', 'course registration', 'class schedule'])) return 'academic_records';
  return 'academic_records';
}

function normalizeDepartmentId(value, text) {
  const raw = String(value || '').trim();
  if (DEPARTMENT_EMAILS[raw]) return raw;
  if (LEGACY_DEPARTMENT_ALIASES[raw]) return LEGACY_DEPARTMENT_ALIASES[raw];
  return inferDepartment(text);
}

function applyDepartmentFields(target, departmentId) {
  const safeId = DEPARTMENT_EMAILS[departmentId] ? departmentId : 'academic_records';
