  '안내 페이지', '어디에서 확인', '어디서 확인'
];
const QUESTION_HINTS = ['언제', '기간', '일정', '방법', '어디', '어디서', '어디에서', '확인 위치', '안내', '페이지', '마감일'];
const RISKY_KEYWORDS = [
