];
function bool(value) { return value === true; }
function num(value) {
  let n = Number(value);
  if (!Number.isFinite(n)) return 0;
  if (n > 1) n = n / 100;
  return Math.max(0, Math.min(1, n));
}
function normalizeCoreAction(value) {
  const action = String(value || '').trim().toLowerCase();
  if (action === 'auto' || action === 'auto_reply' || action === 'auto_reply_from_core' || action === 'faq') return 'auto_reply';
